/**
 * 描述结构放置旋转的枚举。
 *
 * Enum describing a structure's placement rotation.
 */
export enum StructureRotation {
    /**
     * @remarks
     * 不旋转。
     *
     * No rotation.
     *
     */
    None = 'None',
    /**
     * @remarks
     * 180 度旋转。
     *
     * 180 degree rotation.
     *
     */
    Rotate180 = 'Rotate180',
    /**
     * @remarks
     * 270 度旋转。
     *
     * 270 degree rotation.
     *
     */
    Rotate270 = 'Rotate270',
    /**
     * @remarks
     * 90 度旋转。
     *
     * 90 degree rotation.
     *
     */
    Rotate90 = 'Rotate90',
}
